import { cva, type VariantProps } from "class-variance-authority";
import * as React from "react";

import { cn } from "@/lib/utils";

const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-xl text-sm font-medium transition-colors duration-150 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring disabled:pointer-events-none disabled:opacity-50",
  {
    variants: {
      variant: {
        default:
          "bg-primary text-primary-foreground shadow-panel hover:bg-primary/90",
        secondary:
          "bg-secondary text-secondary-foreground hover:bg-secondary/80",
        ghost: "text-foreground hover:bg-foreground/5",
        outline:
          "border border-border bg-card/70 text-foreground hover:bg-foreground/5",
      },
      size: {
        default: "h-11 px-4 py-2",
        sm: "h-9 rounded-lg px-3",
        lg: "h-12 rounded-2xl px-5 text-base",
        icon: "h-9 w-9 rounded-lg",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  },
);

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {}

export const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, ...props }, ref) => (
    <button
      ref={ref}
      className={cn(buttonVariants({ variant, size }), className)}
      {...props}
    />
  ),
);

Button.displayName = "Button";

import { cva, type VariantProps } from "class-variance-authority";
import type * as React from "react";

import { cn } from "@/lib/utils";

const badgeVariants = cva(
  "inline-flex items-center rounded-full border px-2.5 py-1 text-xs font-medium uppercase tracking-[0.18em]",
  {
    variants: {
      variant: {
        default: "border-primary/20 bg-primary/10 text-primary",
        secondary: "border-border bg-secondary text-secondary-foreground",
        outline: "border-border/80 bg-background/60 text-foreground",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  },
);

export interface BadgeProps
  extends React.HTMLAttributes<HTMLDivElement>,
    VariantProps<typeof badgeVariants> {}

export function Badge({ className, variant, ...props }: BadgeProps) {
  return (
    <div className={cn(badgeVariants({ variant }), className)} {...props} />
  );
}

import type { ImportJob } from "@chat-exporter/shared";
import { Clock3, LoaderCircle } from "lucide-react";

import { getJobStatusLabel } from "@/components/format-workspace/labels";
import { SaveIndicator } from "@/components/format-workspace/save-indicator";
import { Badge } from "@/components/ui/badge";

type ActiveStage = {
  detail: string;
  label: string;
} | null;

type StatusHeaderProps = {
  activeStage: ActiveStage;
  elapsedTime: string;
  hasEdits?: boolean;
  isSaving?: boolean;
  job: ImportJob;
};

export function StatusHeader({
  activeStage,
  elapsedTime,
  hasEdits = false,
  isSaving = false,
  job,
}: StatusHeaderProps) {
  return (
    <div className="flex flex-wrap items-center gap-3">
      <Badge variant={job.status === "completed" ? "default" : "outline"}>
        {getJobStatusLabel(job.status)}
      </Badge>
      {job.summary ? (
        <p className="text-sm text-muted-foreground">
          {job.summary.messageCount} Nachrichten В· {job.summary.transcriptWords}{" "}
          WГ¶rter
        </p>
      ) : null}
      <SaveIndicator isSaving={isSaving} hasEdits={hasEdits} />
      {job.status !== "completed" && activeStage ? (
        <div className="inline-flex items-center gap-2 text-sm text-muted-foreground">
          {job.status === "queued" ? (
            <Clock3 className="h-4 w-4" />
          ) : (
            <LoaderCircle className="h-4 w-4 animate-spin" />
          )}
          <span>{activeStage.label}</span>
          <span>В·</span>
          <span>{elapsedTime}</span>
        </div>
      ) : null}
    </div>
  );
}

