 1вҶ’import type { ImportSummary } from "@chat-exporter/shared";
 2вҶ’import { useMutation } from "@tanstack/react-query";
 3вҶ’import { useEffect } from "react";
 4вҶ’
 5вҶ’import { Button } from "@/components/ui/button";
 6вҶ’import { rpc } from "@/lib/rpc";
 7вҶ’
 8вҶ’interface DeleteImportDialogProps {
 9вҶ’  import_: ImportSummary;
10вҶ’  onClose: () => void;
11вҶ’  onDeleted: () => void;
12вҶ’}
13вҶ’
14вҶ’export function DeleteImportDialog({
15вҶ’  import_,
16вҶ’  onClose,
17вҶ’  onDeleted,
18вҶ’}: DeleteImportDialogProps) {
19вҶ’  const title = import_.pageTitle || import_.sourceUrl;
20вҶ’
21вҶ’  const deleteMutation = useMutation({
22вҶ’    mutationFn: () => rpc.imports.delete({ id: import_.id }),
23вҶ’    onSuccess: () => onDeleted(),
24вҶ’  });
25вҶ’
26вҶ’  useEffect(() => {
27вҶ’    function handleKeyDown(e: KeyboardEvent) {
28вҶ’      if (e.key === "Escape") onClose();
29вҶ’    }
30вҶ’    document.addEventListener("keydown", handleKeyDown);
31вҶ’    return () => document.removeEventListener("keydown", handleKeyDown);
32вҶ’  }, [onClose]);
33вҶ’
34вҶ’  return (
35вҶ’    <div
36вҶ’      aria-modal="true"
37вҶ’      className="fixed inset-0 z-50 flex items-center justify-center bg-black/50"
38вҶ’      role="dialog"
39вҶ’    >
40вҶ’      <div className="mx-4 w-full max-w-md rounded-xl border border-border bg-card p-6 shadow-lg">
41вҶ’        <h2 className="mb-2 text-lg font-semibold">Import lГ¶schen</h2>
42вҶ’        <p className="mb-6 text-sm text-muted-foreground">
43вҶ’          Import &ldquo;
44вҶ’          {title.length > 60 ? `${title.slice(0, 57)}...` : title}
45вҶ’          &rdquo; wirklich lГ¶schen? Diese Aktion kann nicht rГјckgГӨngig gemacht
46вҶ’          werden.
47вҶ’        </p>
48вҶ’
49вҶ’        {deleteMutation.error ? (
50вҶ’          <div className="mb-4 rounded-lg border border-red-300/40 bg-red-100/60 px-3 py-2 text-sm text-red-900">
51вҶ’            {deleteMutation.error.message}
52вҶ’          </div>
53вҶ’        ) : null}
54вҶ’
55вҶ’        <div className="flex justify-end gap-3">
56вҶ’          <Button
57вҶ’            disabled={deleteMutation.isPending}
58вҶ’            variant="ghost"
59вҶ’            onClick={onClose}
60вҶ’          >
61вҶ’            Abbrechen
62вҶ’          </Button>
63вҶ’          <Button
64вҶ’            className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
65вҶ’            disabled={deleteMutation.isPending}
66вҶ’            onClick={() => deleteMutation.mutate()}
67вҶ’          >
68вҶ’            {deleteMutation.isPending ? "Wird gelГ¶scht..." : "LГ¶schen"}
69вҶ’          </Button>
70вҶ’        </div>
71вҶ’      </div>
72вҶ’    </div>
73вҶ’  );
74вҶ’}
