 54вҶ’const modalLabels = {
 55вҶ’  title: "Formatierungsregeln",
 56вҶ’  description: "Alle aktiven Regeln fГјr diesen Import verwalten.",
 57вҶ’  searchPlaceholder: "Regeln durchsuchen...",
 58вҶ’  noResults: "Keine Regeln gefunden.",
 59вҶ’  scopeAll: "Alle Imports",
 60вҶ’  scopeLocal: "Nur dieser Import",
 61вҶ’  disable: "Deaktivieren",
 62вҶ’  disabling: "Wird deaktiviert...",
 63вҶ’  delete: "LГ¶schen",
 64вҶ’  deleting: "Wird gelГ¶scht...",
