 74вҶ’
 75вҶ’function sortRules(
 76вҶ’  rules: FormatRule[],
 77вҶ’  sortKey: SortKey,
 78вҶ’  sortDir: SortDir,
 79вҶ’): FormatRule[] {
 80вҶ’  return [...rules].sort((a, b) => {
 81вҶ’    let cmp: number;
 82вҶ’    switch (sortKey) {
 83вҶ’      case "title":
 84вҶ’        cmp = a.instruction.localeCompare(b.instruction, "de");
 85вҶ’        break;
 86вҶ’      case "scope":
 87вҶ’        cmp = (scopeOrder[a.scope] ?? 2) - (scopeOrder[b.scope] ?? 2);
 88вҶ’        break;
 89вҶ’      default:
 90вҶ’        cmp = new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime();
 91вҶ’        break;
 92вҶ’    }
 93вҶ’    return sortDir === "desc" ? -cmp : cmp;
 94вҶ’  });
 95вҶ’}
 96вҶ’
 97вҶ’function describeSelectorStrategy(selector: unknown): string {
 98вҶ’  const s =
 99вҶ’    selector && typeof selector === "object"
100вҶ’      ? (selector as Record<string, unknown>)
101вҶ’      : null;
102вҶ’  if (!s) return "Unbekannter Selektor";
103вҶ’
104вҶ’  const strategy = s.strategy as string | undefined;
105вҶ’  const blockType =
106вҶ’    typeof s.blockType === "string" ? getBlockTypeLabel(s.blockType) : null;
107вҶ’
108вҶ’  switch (strategy) {
109вҶ’    case "exact":
110вҶ’      return blockType
111вҶ’        ? `Exakter Block: ${blockType} #${(s.blockIndex as number) + 1}`
112вҶ’        : "Exakter Block";
113вҶ’    case "block_type":
114вҶ’      return blockType
115вҶ’        ? `Alle BlГ¶cke vom Typ: ${blockType}`
116вҶ’        : "Alle BlГ¶cke eines Typs";
117вҶ’    case "prefix_before_colon":
118вҶ’      return blockType
119вҶ’        ? `PrГӨfix vor Doppelpunkt in: ${blockType}`
120вҶ’        : "PrГӨfix vor Doppelpunkt";
121вҶ’    case "markdown_table":
122вҶ’      return "Alle Markdown-Tabellen";
123вҶ’    case "compound": {
124вҶ’      const parts: string[] = [];
125вҶ’
126вҶ’      if (blockType) parts.push(blockType);
127вҶ’
128вҶ’      const role = typeof s.messageRole === "string" ? s.messageRole : null;
129вҶ’      if (role) parts.push(`Rolle: ${role}`);
130вҶ’
131вҶ’      const level = typeof s.headingLevel === "number" ? s.headingLevel : null;
132вҶ’      if (level) parts.push(`H${level}`);
133вҶ’
134вҶ’      const pos = typeof s.position === "string" ? s.position : null;
135вҶ’      if (pos) parts.push(pos === "first" ? "Erster Block" : "Letzter Block");
136вҶ’
137вҶ’      const pattern = typeof s.textPattern === "string" ? s.textPattern : null;
138вҶ’      if (pattern) parts.push(`Pattern: "${pattern}"`);
139вҶ’
140вҶ’      const ctx =
141вҶ’        s.context && typeof s.context === "object"
142вҶ’          ? (s.context as Record<string, unknown>)
143вҶ’          : null;
144вҶ’      if (ctx?.previousSibling) parts.push("nach bestimmtem Block");
145вҶ’      if (ctx?.nextSibling) parts.push("vor bestimmtem Block");
146вҶ’
147вҶ’      return parts.length > 0
148вҶ’        ? `Compound: ${parts.join(", ")}`
149вҶ’        : "Compound-Filter (alle BlГ¶cke)";
150вҶ’    }
151вҶ’    default:
152вҶ’      return `Strategie: ${strategy ?? "unbekannt"}`;
153вҶ’  }
154вҶ’}
